export const VOCAB = {
  mineral: "A pure natural substance, like quartz or calcite, that rocks are built from.",
  rock: "A natural mix of one or more minerals stuck together — like a cake made of mineral ingredients.",
  hardness: "How well a mineral resists being scratched. Testers compare it to a fingernail, a penny, and a steel nail.",
  streak: "The color of a mineral's powder when rubbed on rough tile — often truer than the color on the outside.",
  crystal: "A solid where the tiny building blocks line up in a neat, repeating pattern, giving it flat faces and straight edges.",
  luster: "How a mineral's surface shines — glassy, metallic, or dull.",
  cleavage: "The way some minerals break along smooth, flat planes every time, like a book falling open to the same page.",
  fracture: "The way some minerals break raggedly, with no flat plane, instead of cleaving neatly.",
  igneous: "Rock formed when melted rock (magma or lava) cools and hardens.",
  sedimentary: "Rock formed from layers of sand, mud, or shells that settled and got pressed together over time.",
  metamorphic: "Rock that started as one kind of rock and was changed into another by heat and pressure, without fully melting.",
  magma: "Melted rock still underground.",
  lava: "Melted rock that has reached the surface.",
  stratum: "One single layer of rock or sediment. (More than one layer: strata.)",
  strata: "More than one stratum — layers of rock stacked one on top of another.",
  "rock cycle": "The ongoing journey a rock can take between the igneous, sedimentary, and metamorphic families.",
  weathering: "Rock being broken down into smaller pieces by wind, water, ice, or time — without being moved away yet.",
  erosion: "Broken-down rock and soil being carried away, usually by water, wind, or ice.",
  deposition: "Material settling down and being laid in place after being carried by water, wind, or ice.",
  fossil: "A preserved trace of something that lived long ago — a shell, bone, footprint, or leaf kept safe inside rock.",
  fossilization: "The process of a living thing being preserved as a fossil — it requires being buried very quickly.",
  paleontology: "The study of fossils and the ancient living things they came from.",
  "index fossil": "A fossil from a creature that lived only during one time period, used to help date the rock layer it's found in.",
  "geological column": "A composite chart built from rock layers observed all around the world — no single place on Earth has the whole thing in one spot.",
  extinction: "When every member of a kind of living thing has died out and none are left.",
  "Cambrian Explosion": "A sudden, surprising burst in the fossil record where most major animal body types appear together, with few simpler ancestors found below.",
  uniformitarianism: "The idea that today's rates and processes can explain all of Earth's past changes, without needing sudden catastrophic events.",
  catastrophism: "The idea that some of Earth's biggest features were shaped by sudden, large-scale, catastrophic events rather than only slow change.",
  unconformity: "A gap in the rock layers where you can see that time passed and material went missing or was worn away before the next layer was laid down.",
  "deep time": "The idea that the earth's history stretches back an enormous, almost unimaginable number of years.",
  glacier: "A huge, slow-moving river of ice that carves valleys and carries rock material with it.",
  moraine: "A ridge of rock and soil left behind by a melting or retreating glacier.",
  erratic: "A boulder carried far from where it started by a glacier, then left behind when the ice melted.",
  observation: "Something you notice directly by looking, testing, or measuring — before adding any explanation.",
  inference: "A careful guess or conclusion you build on top of an observation, using some added assumption.",
};
